    public static class ReviewFormatting
    {
        public static IHtmlString ToSafeHtml(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
                return MvcHtmlString.Empty;

            var encoded = HttpUtility.HtmlEncode(input);

            // Simple allowed formatting:
            // **bold** or __bold__
            // *italic* or _italic_
            // Newlines -> <br/>
            var s = encoded;

            // Normalize CRLF
            s = s.Replace("\r\n", "\n").Replace("\r", "\n");

            s = ReplacePaired(s, "**", "<strong>", "</strong>");
            s = ReplacePaired(s, "__", "<strong>", "</strong>");
            s = ReplacePaired(s, "*", "<em>", "</em>");
            s = ReplacePaired(s, "_", "<em>", "</em>");

            s = s.Replace("\n", "<br/>");

            return new MvcHtmlString(s);
        }

        private static string ReplacePaired(string input, string token, string openTag, string closeTag)
        {
            if (string.IsNullOrEmpty(input)) return input;

            var sb = new StringBuilder(input.Length);
            int idx = 0;
            bool open = false;

            while (idx < input.Length)
            {
                int next = input.IndexOf(token, idx, StringComparison.Ordinal);
                if (next < 0)
                {
                    sb.Append(input, idx, input.Length - idx);
                    break;
                }

                sb.Append(input, idx, next - idx);

                // Avoid toggling on empty spans like ****, ____, etc.
                // If the token is immediately followed by the same token, treat as literal.
                int after = next + token.Length;
                if (after <= input.Length - token.Length &&
                    string.Compare(input, after, token, 0, token.Length, StringComparison.Ordinal) == 0)
                {
                    sb.Append(token);
                    idx = after;
                    continue;
                }

                sb.Append(open ? closeTag : openTag);
                open = !open;
                idx = after;
            }

            // If unbalanced, revert the last tag to literal token by simple heuristic:
            // If open is true, we emitted an opening tag without a closing tag. Replace the last openTag with token.
            if (open)
            {
                var result = sb.ToString();
                int pos = result.LastIndexOf(openTag, StringComparison.Ordinal);
                if (pos >= 0)
                {
                    result = result.Remove(pos, openTag.Length).Insert(pos, token);
                }
                return result;
            }

            return sb.ToString();
        }
    }

